    public List<EndorsementConfirmedEventResponse> getEndorsementConfirmedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(ENDORSEMENTCONFIRMED_EVENT, transactionReceipt);
        ArrayList<EndorsementConfirmedEventResponse> responses = new ArrayList<EndorsementConfirmedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            EndorsementConfirmedEventResponse typedResponse = new EndorsementConfirmedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.receiptId = (byte[]) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.fromHash = (byte[]) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.newOwner = (String) eventValues.getIndexedValues().get(2).getValue();
            typedResponse.toHash = (byte[]) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

